import { useForm, useWatch } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useEffect, useState } from 'react';

// Schéma pour une adresse
const addressSchema = z.object({
  country: z.string().min(1, 'Choisissez un pays'),
  city: z.string().min(1, 'Choisissez une ville'),
  postalCode: z.string().regex(/^[0-9]{5}$/, 'Code postal à 5 chiffres'),
  street: z.string().min(5, 'Adresse complète requise')
});

// Schéma principal avec champ conditionnel
const checkoutSchema = z.discriminatedUnion('useDifferentBilling', [
  z.object({
    useDifferentBilling: z.literal(false),
    shippingAddress: addressSchema
  }),
  z.object({
    useDifferentBilling: z.literal(true),
    shippingAddress: addressSchema,
    billingAddress: addressSchema
  })
]);

type CheckoutFormData = z.infer<typeof checkoutSchema>;

// Simule le chargement des villes par pays
const citiesByCountry: Record<string, string[]> = {
  France: ['Paris', 'Lyon', 'Marseille'],
  Cameroun: ['Douala', 'Yaoundé', 'Garoua'],
  Canada: ['Montréal', 'Toronto', 'Vancouver']
};

const AddressForm = ({ prefix, label }: { prefix: 'shippingAddress' | 'billingAddress', label: string }) => {
  const country = useWatch({ name: `${prefix}.country` });
  const [cities, setCities] = useState<string[]>([]);

  useEffect(() => {
    setCities(citiesByCountry[country] || []);
  }, [country]);

  return (
    <fieldset className="border p-4 rounded mb-4">
      <legend className="font-bold">{label}</legend>
      <select {...register(`${prefix}.country`)} className="border p-2 w-full mb-2">
        <option value="">Sélectionnez un pays</option>
        <option>France</option>
        <option>Cameroun</option>
        <option>Canada</option>
      </select>
      {errors[prefix]?.country && <p className="text-red-500">{errors[prefix].country.message}</p>}

      <select {...register(`${prefix}.city`)} className="border p-2 w-full mb-2" disabled={!cities.length}>
        <option value="">Sélectionnez une ville</option>
        {cities.map(city => <option key={city}>{city}</option>)}
      </select>
      {errors[prefix]?.city && <p className="text-red-500">{errors[prefix].city.message}</p>}

      <input {...register(`${prefix}.postalCode`)} placeholder="Code postal" className="border p-2 w-full mb-2" />
      {errors[prefix]?.postalCode && <p className="text-red-500">{errors[prefix].postalCode.message}</p>}

      <input {...register(`${prefix}.street`)} placeholder="Adresse" className="border p-2 w-full mb-2" />
      {errors[prefix]?.street && <p className="text-red-500">{errors[prefix].street.message}</p>}
    </fieldset>
  );
};

const CheckoutForm = () => {
  const { register, handleSubmit, control, formState: { errors } } = useForm<CheckoutFormData>({
    resolver: zodResolver(checkoutSchema),
    defaultValues: {
      useDifferentBilling: false,
      shippingAddress: { country: '', city: '', postalCode: '', street: '' }
    }
  });

  const useDifferentBilling = useWatch({ control, name: 'useDifferentBilling' });

  const onSubmit = (data: CheckoutFormData) => {
    console.log('Commande validée:', data);
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="max-w-lg mx-auto p-4">
      <AddressForm prefix="shippingAddress" label="Adresse de livraison" />

      <label className="flex items-center gap-2 my-4">
        <input type="checkbox" {...register('useDifferentBilling')} />
        Utiliser une adresse de facturation différente
      </label>

      {useDifferentBilling && (
        <AddressForm prefix="billingAddress" label="Adresse de facturation" />
      )}

      <button type="submit" className="bg-green-600 text-white p-2 rounded w-full">
        Valider la commande
      </button>
    </form>
  );
};
